import React, { useEffect, useState } from 'react';
import ResumeService from '../services/ResumeService';
import jsPDF from 'jspdf';

function AllResumes() {

  const [resumes, setResumes] = useState([]);
  const [editingId, setEditingId] = useState(null);
  const [editedResume, setEditedResume] = useState({});

  // ================= LOAD RESUMES =================

  useEffect(() => {
    fetchResumes();
  }, []);

  const fetchResumes = async () => {
    try {
      const response = await ResumeService.getAllResumes();
      setResumes(response.data);
    } catch (error) {
      console.log(error);
      alert('Failed To Load Resumes');
    }
  };

  // ================= DELETE =================

  const deleteResume = async (id) => {
    try {
      await ResumeService.deleteResume(id);
      alert('Resume Deleted Successfully');
      fetchResumes();
    } catch (error) {
      console.log(error);
      alert('Delete Failed');
    }
  };

  // ================= EDIT =================

  const startEdit = (resume) => {
    setEditingId(resume.id);
    setEditedResume(resume);
  };

  const handleChange = (e) => {
    setEditedResume({
      ...editedResume,
      [e.target.name]: e.target.value
    });
  };

  const updateResume = async () => {
    try {
      await ResumeService.updateResume(editingId, editedResume);
      alert('Resume Updated Successfully');
      setEditingId(null);
      fetchResumes();
    } catch (error) {
      console.log(error);
      alert('Update Failed');
    }
  };

  // ================= DOWNLOAD PDF =================

  const downloadResume = (resume) => {

    const doc = new jsPDF();

    doc.setFontSize(16);
    doc.text("RESUME", 20, 20);

    doc.setFontSize(12);

    doc.text(`Name: ${resume.fullName || ''}`, 20, 40);
    doc.text(`Email: ${resume.email || ''}`, 20, 50);
    doc.text(`Phone: ${resume.phone || ''}`, 20, 60);

    doc.text(`Summary: ${resume.summary || ''}`, 20, 70);
    doc.text(`Skills: ${resume.skills || ''}`, 20, 80);
    doc.text(`Education: ${resume.education || ''}`, 20, 90);
    doc.text(`Experience: ${resume.experience || ''}`, 20, 100);
    doc.text(`Projects: ${resume.projects || ''}`, 20, 110);
    doc.text(`Languages: ${resume.languages || ''}`, 20, 120);
    doc.text(`Hobbies: ${resume.hobbies || ''}`, 20, 130);

    doc.save(`${resume.fullName}_resume.pdf`);
  };

  // ================= UI =================

  return (

    <div className="container mt-5 mb-5">

      <h1 className="mb-4">All Resumes</h1>

      {resumes.length === 0 ? (
        <h4>No Resume Found</h4>
      ) : (

        resumes.map((resume) => (

          <div className="card shadow p-4 mb-4" key={resume.id}>

            {/* ================= EDIT MODE ================= */}

            {editingId === resume.id ? (

              <div>

                <h4>Edit Resume</h4>

                <input
                  name="fullName"
                  value={editedResume.fullName || ''}
                  onChange={handleChange}
                  className="form-control mb-2"
                />

                <input
                  name="email"
                  value={editedResume.email || ''}
                  onChange={handleChange}
                  className="form-control mb-2"
                />

                <input
                  name="phone"
                  value={editedResume.phone || ''}
                  onChange={handleChange}
                  className="form-control mb-2"
                />

                <textarea
                  name="summary"
                  value={editedResume.summary || ''}
                  onChange={handleChange}
                  className="form-control mb-2"
                  rows="3"
                />

                <textarea
                  name="skills"
                  value={editedResume.skills || ''}
                  onChange={handleChange}
                  className="form-control mb-2"
                  rows="2"
                />

                <textarea
                  name="education"
                  value={editedResume.education || ''}
                  onChange={handleChange}
                  className="form-control mb-2"
                  rows="2"
                />

                <textarea
                  name="experience"
                  value={editedResume.experience || ''}
                  onChange={handleChange}
                  className="form-control mb-2"
                  rows="2"
                />

                <textarea
                  name="projects"
                  value={editedResume.projects || ''}
                  onChange={handleChange}
                  className="form-control mb-2"
                  rows="2"
                />

                <textarea
                  name="languages"
                  value={editedResume.languages || ''}
                  onChange={handleChange}
                  className="form-control mb-2"
                  rows="1"
                />

                <textarea
                  name="hobbies"
                  value={editedResume.hobbies || ''}
                  onChange={handleChange}
                  className="form-control mb-3"
                  rows="1"
                />

                <button className="btn btn-success me-2" onClick={updateResume}>
                  Save
                </button>

                <button className="btn btn-secondary" onClick={() => setEditingId(null)}>
                  Cancel
                </button>

              </div>

            ) : (

              // ================= VIEW MODE =================

              <div className="row">

                <div className="col-md-3">

                  {resume.profileImage && (
                    <img
                      src={resume.profileImage}
                      alt="Profile"
                      className="img-fluid rounded-circle"
                      style={{ width: '150px', height: '150px', objectFit: 'cover' }}
                    />
                  )}

                </div>

                <div className="col-md-9">

                  <h3>{resume.fullName}</h3>

                  <p><b>Email:</b> {resume.email}</p>
                  <p><b>Phone:</b> {resume.phone}</p>
                  <p><b>Summary:</b> {resume.summary}</p>
                  <p><b>Skills:</b> {resume.skills}</p>
                  <p><b>Education:</b> {resume.education}</p>
                  <p><b>Experience:</b> {resume.experience}</p>
                  <p><b>Projects:</b> {resume.projects}</p>
                  <p><b>Languages:</b> {resume.languages}</p>
                  <p><b>Hobbies:</b> {resume.hobbies}</p>

                  <button
                    className="btn btn-primary me-2"
                    onClick={() => startEdit(resume)}
                  >
                    Edit
                  </button>

                  <button
                    className="btn btn-success me-2"
                    onClick={() => downloadResume(resume)}
                  >
                    Download
                  </button>

                  <button
                    className="btn btn-danger"
                    onClick={() => deleteResume(resume.id)}
                  >
                    Delete
                  </button>

                </div>

              </div>

            )}

          </div>

        ))

      )}

    </div>
  );
}

export default AllResumes;
